class Solution:
    def numFactoredBinaryTrees(self, arr):
        MOD = 10**9 + 7
        s = sorted(arr)
        idx = {v: i for i, v in enumerate(s)}
        present = set(s)
        dp = [1] * len(s)
        for i, v in enumerate(s):
            for a in s[:i]:
                if v % a == 0:
                    b = v // a
                    if b in present:
                        dp[i] += dp[idx[a]] * dp[idx[b]]
        return sum(dp) % MOD

