class Solution:
    def numFactoredBinaryTrees(self, arr):
        MOD = 10**9 + 7
        s = sorted(arr)
        dp = {}
        for v in s:
            total = 1
            for a in s:
                if a * a > v:
                    break
                if v % a == 0:
                    b = v // a
                    if b in dp:
                        if a == b:
                            total += dp[a] * dp[b]
                        else:
                            total += 2 * dp[a] * dp[b]
            dp[v] = total % MOD
        return sum(dp.values()) % MOD

