var numFactoredBinaryTrees = function(arr) {
    const MOD = 1000000007n;
    const s = arr.slice().sort((a, b) => a - b);
    const dp = new Map();
    for (const v of s) {
        let total = 1n;
        for (const a of s) {
            if (a * a > v) break;
            if (v % a === 0) {
                const b = v / a;
                if (dp.has(b)) {
                    if (a === b) total += dp.get(a) * dp.get(b);
                    else total += 2n * dp.get(a) * dp.get(b);
                }
            }
        }
        dp.set(v, total % MOD);
    }
    let sum = 0n;
    for (const val of dp.values()) sum += val;
    return Number(sum % MOD);
};
